 (function () { const lang = navigator.language || navigator.userLanguage || "en"; const supportedLangs = [ "ja", "en", "it", "es", "el", "hi", "pl", "zh", "fr", "de", "ko", "pt", "ru", "ar", "nl", "vi", "et", "th", "cs", "da" ]; const activeLang = supportedLangs.includes(lang.slice(0, 2)) ? lang.slice(0, 2) : "en"; const keys = ["copy", "email", "blog", "follow", "search", "thanks"]; const translations = {}; let completed = 0; function applyTranslations() { window._weshareLangMap = translations; } function fetchTranslation(key) { const url = `https://weshare-ai-language.vercel.app/api/translate?lang=${activeLang}&text=${encodeURIComponent(key)}`; return fetch(url) .then(res => res.json()) .then(data => { translations[key] = (data.translation || key).replace(/^"+|"+$/g, ""); completed++; if (completed === keys.length) applyTranslations(); }) .catch(() => { translations[key] = key; completed++; if (completed === keys.length) applyTranslations(); }); } keys.forEach(fetchTranslation); })(); 